#include <vector>
#include <algorithm>

using namespace std;

long long solve(vector<long long> prices, vector<long long> strategy, long long k) {
    int n = prices.size();
    long long original_profit = 0;
    for (int i = 0; i < n; ++i) {
        original_profit += strategy[i] * prices[i];
    }

    vector<long long> prefix_strategy(n + 1, 0);
    vector<long long> prefix_prices(n + 1, 0);

    for (int i = 0; i < n; ++i) {
        prefix_strategy[i + 1] = prefix_strategy[i] + strategy[i] * prices[i];
        prefix_prices[i + 1] = prefix_prices[i] + prices[i];
    }

    long long max_gain = 0;
    long long half_k = k / 2;

    for (int i = 0; i <= n - k; ++i) {
        long long sum_original = prefix_strategy[i + k] - prefix_strategy[i];
        long long sum_second_half = prefix_prices[i + k] - prefix_prices[i + half_k];
        long long gain = sum_second_half - sum_original;
        if (gain > max_gain) {
            max_gain = gain;
        }
    }

    return original_profit + max_gain;
}

